const PRE_BRUNA_VERSION = "v2_contexto_base_conhecimento";

function readNode(name) {
  try {
    return $(name).first().json || {};
  } catch (error) {
    return {};
  }
}

const entrada = readNode("Converter Payload");
const interpretacao = readNode("Interpreta Audio ou Texto");
const historico = readNode("Busca Histórico Chatwoot");

function clean(value, preserveNewLines = false) {
  let text = "";

  if (value === undefined || value === null) {
    text = "";
  } else if (typeof value === "object") {
    try {
      text = JSON.stringify(value);
    } catch (error) {
      text = "";
    }
  } else {
    text = String(value);
  }

  text = text
    .replace(/\[object Object\]/gi, "")
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, " ")
    .replace(/\uFFFD/g, " ")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n");

  if (preserveNewLines) {
    return text
      .split("\n")
      .map(line => line.replace(/[ \t]+/g, " ").trim())
      .filter(Boolean)
      .join("\n")
      .trim();
  }

  return text.replace(/\s+/g, " ").trim();
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value, true);
    if (text) return text;
  }
  return "";
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function extractInterpretedMessage(data) {
  const msg = data?.message;

  if (typeof msg === "string") {
    return { content: clean(msg, true) };
  }

  if (msg && typeof msg === "object") {
    return {
      ...msg,
      content: firstFilled(
        msg.content,
        msg.text,
        msg.transcription,
        msg.transcribed_text,
        msg.message
      )
    };
  }

  return {
    content: firstFilled(
      data?.content,
      data?.text,
      data?.transcription,
      data?.transcribed_text,
      data?.output,
      data?.message
    )
  };
}

function extractRows(value) {
  if (!value) return [];
  if (Array.isArray(value)) return value;

  if (typeof value === "object") {
    for (const key of ["matches", "data", "rows", "documents", "payload", "result", "results"]) {
      if (Array.isArray(value[key])) return value[key];
    }
  }

  return [value];
}

function formatKnowledgeRow(row, index) {
  if (row === undefined || row === null) return "";

  if (typeof row === "string") {
    const text = clean(row, true);
    return text ? `[${index + 1}] ${text}` : "";
  }

  if (typeof row !== "object") {
    const text = clean(row, true);
    return text ? `[${index + 1}] ${text}` : "";
  }

  const title = firstFilled(row.titulo, row.title, row.pergunta, row.question, row.assunto, row.topic);
  const content = firstFilled(row.conteudo, row.content, row.texto, row.text, row.resposta, row.answer, row.document);
  const source = firstFilled(row.arquivo_origem, row.source, row.origem, row.metadata?.source);
  const score = firstFilled(row.score, row.similarity, row.distance);

  if (!content && !title) return "";

  return [
    `[${index + 1}]${title ? ` ${title}` : ""}`,
    source ? `Fonte: ${source}` : "",
    score ? `Score: ${score}` : "",
    content
  ].filter(Boolean).join("\n");
}

function readKnowledgeContext() {
  const currentAgent = asObject($json.agent);

  const currentContext = firstFilled(
    currentAgent.knowledge_base_text,
    currentAgent.knowledge_context,
    $json.knowledge_base_text,
    $json.knowledge_context
  );

  if (currentContext) {
    return {
      source_node: "input_atual",
      context: currentContext,
      rows_count: Number(currentAgent.knowledge_base_count || $json.knowledge_base_count || 1)
    };
  }

  const candidates = [
    "Formata Base Conhecimento",
    "Busca Base Conhecimento",
    "Busca Base de Conhecimento",
    "Busca FAQ Bruna",
    "Consulta Base Bruna",
    "Supabase Busca Base",
    "Supabase FAQ"
  ];

  for (const nodeName of candidates) {
    const data = readNode(nodeName);
    if (!Object.keys(data).length) continue;

    const direct = firstFilled(
      data.agent?.knowledge_base_text,
      data.knowledge_base_text,
      data.knowledge_context,
      data.context,
      data.contexto,
      data.conteudo,
      data.content,
      data.text
    );

    if (direct) {
      return {
        source_node: nodeName,
        context: direct,
        rows_count: Number(data.agent?.knowledge_base_count || data.knowledge_base_count || 1)
      };
    }

    const rows = extractRows(data);
    const formatted = rows
      .map(formatKnowledgeRow)
      .filter(Boolean)
      .slice(0, 8)
      .join("\n\n");

    if (formatted) {
      return {
        source_node: nodeName,
        context: formatted,
        rows_count: rows.length
      };
    }
  }

  return {
    source_node: "",
    context: "",
    rows_count: 0
  };
}

function classifyBusinessKnowledgeNeed(text) {
  const value = clean(text).toLowerCase();

  const checks = [
    ["localizacao_endereco", /\b(onde fica|onde vocês ficam|localiza|localização|endereço|bairro|cidade|unidade|patamares|amaralina|pituba)\b/i],
    ["preco_valor", /\b(preço|valor|diária|diaria|mensal|plano|pacote|quanto custa|custa quanto|taxa|avaliação|avaliacao)\b/i],
    ["horario_funcionamento", /\b(horário|horario|funciona|funcionamento|abre|fecha|check[- ]?in|check[- ]?out)\b/i],
    ["servicos_regras", /\b(creche|hotel|hospedagem|adaptação|adaptacao|adestramento|transporte|buscar|levar|pegar|trazer|vacina|antipulgas|vermifug)\b/i],
    ["racas_restricoes", /\b(raça|raca|porte|pitbull|rottweiler|akita|american bully|macho não castrado|castrado|cio|idoso)\b/i],
    ["pagamento", /\b(pix|pagamento|paguei|comprovante|boleto|depósito|deposito|transferência|transferencia)\b/i]
  ];

  const matched = checks
    .filter(([, regex]) => regex.test(value))
    .map(([name]) => name);

  return {
    needs_business_knowledge: matched.length > 0,
    intents: matched
  };
}

const baseMessage = asObject(entrada.message);
const interpretedMessage = extractInterpretedMessage(interpretacao);

const interpretedContent = clean(interpretedMessage.content, true);
const baseContent = clean(baseMessage.content, true);
const baseContentForAi = clean(baseMessage.content_for_ai, true);

const finalContent = firstFilled(
  interpretedContent,
  baseContent,
  baseContentForAi,
  entrada.chatInput
);

const message = {
  ...baseMessage,
  ...interpretedMessage,
  content: finalContent,
  content_raw: baseContent,
  content_before_interpretation: baseContent,
  content_for_ai: finalContent,
  has_text: Boolean(finalContent),
  has_attachment: baseMessage.has_attachment === true,
  content_type: baseMessage.content_type || baseMessage.message_modality || interpretedMessage.content_type || "text_only",
  message_modality: baseMessage.message_modality || baseMessage.content_type || interpretedMessage.message_modality || "text_only",
  data_url: baseMessage.data_url || interpretedMessage.data_url || null,
  media_type: baseMessage.media_type || interpretedMessage.media_type || "",
  interpretation: {
    used: Boolean(interpretedContent),
    source_node: "Interpreta Audio ou Texto",
    raw_output: interpretacao
  }
};

const historyText = clean(historico.history_text, true);
const historyForBruna = clean(historico.history_for_agent, true);
const knowledge = readKnowledgeContext();
const businessNeed = classifyBusinessKnowledgeNeed(finalContent);

const knowledgeQuery = [
  finalContent,
  businessNeed.intents.length ? `Intenções: ${businessNeed.intents.join(", ")}` : "",
  historyForBruna ? `Contexto recente: ${historyForBruna.split("\n").slice(-6).join(" | ")}` : ""
].filter(Boolean).join("\n");

const agent = {
  ...asObject(entrada.agent),
  ...asObject($json.agent),
  history_text: historyText,
  history_for_agent: historyForBruna,
  history_source: "chatwoot_subworkflow",
  current_message_after_interpretation: finalContent,
  needs_business_knowledge: businessNeed.needs_business_knowledge,
  business_knowledge_intents: businessNeed.intents,
  knowledge_query: knowledgeQuery,
  knowledge_context: knowledge.context,
  knowledge_source_node: knowledge.source_node,
  knowledge_rows_count: knowledge.rows_count
};

const aiInput = [
  "HISTÓRICO RECENTE DA CONVERSA:",
  historyForBruna || "Sem histórico recente disponível.",
  "",
  "MENSAGEM ATUAL DO LEAD:",
  finalContent || "[Mensagem sem texto útil]",
  "",
  "INTERPRETAÇÃO DA MENSAGEM ATUAL:",
  `Modalidade: ${message.message_modality || "unknown"}`,
  `Tem anexo: ${message.has_attachment ? "sim" : "não"}`,
  message.data_url ? `URL do anexo: ${message.data_url}` : "",
  "",
  "NECESSIDADE DE BASE DE CONHECIMENTO:",
  businessNeed.needs_business_knowledge ? "sim" : "não",
  businessNeed.intents.length ? `Assuntos detectados: ${businessNeed.intents.join(", ")}` : "Assuntos detectados: nenhum",
  "",
  "BASE DE CONHECIMENTO RECUPERADA:",
  knowledge.context || "Nenhum trecho de base de conhecimento foi recuperado para esta mensagem.",
  "",
  "DADOS TÉCNICOS DO CONTATO:",
  `Telefone: ${entrada.lead?.phone || "não informado"}`,
  "",
  "OBSERVAÇÃO IMPORTANTE:",
  "Não use o nome de perfil do WhatsApp/Chatwoot como nome confirmado da pessoa.",
  "O nome da pessoa só deve ser considerado confirmado se aparecer claramente no histórico ou na mensagem atual.",
  "",
  "REGRAS PARA ESTA RESPOSTA:",
  "Use o histórico da conversa como fonte principal para o que já foi dito.",
  "Use a BASE DE CONHECIMENTO RECUPERADA como fonte principal para fatos de negócio, como endereço, unidade, preço, horário, transporte, regras, serviços, avaliação, hotel e creche.",
  "Se o lead fizer uma pergunta objetiva de negócio, responda essa pergunta antes de continuar a qualificação.",
  "Se a pergunta exigir fato de negócio e não houver base recuperada relevante, não chute; encaminhe para humano com motivo_handoff='duvida_operacional'.",
  "Não pergunte sobre rotina diária do cão.",
  "Se precisar falar de comportamento, pergunte apenas como o cão costuma ficar com outros cães.",
  "Classifique sempre status_atendimento, proxima_acao e labels_sugeridas.",
  "Responda somente no JSON obrigatório do system prompt."
].filter(Boolean).join("\n");

return [
  {
    json: {
      action: entrada.action || "sendMessage",
      sessionId: entrada.sessionId || "",
      chatInput: finalContent,
      lead: entrada.lead || {},
      message,
      conversation: entrada.conversation || {},
      chatwoot: entrada.chatwoot || {},
      routing: entrada.routing || {},
      agent,
      ai_input: aiInput,
      debug: {
        pre_bruna_version: PRE_BRUNA_VERSION,
        base_message: baseMessage,
        interpreted_message: interpretedMessage,
        history_messages_returned: historico.messages_returned || 0,
        history_found_total: historico.messages_found_total || 0,
        needs_business_knowledge: businessNeed.needs_business_knowledge,
        business_knowledge_intents: businessNeed.intents,
        knowledge_source_node: knowledge.source_node,
        knowledge_rows_count: knowledge.rows_count,
        has_knowledge_context: Boolean(knowledge.context)
      }
    }
  }
];

function readNode(name) {
  try {
    return $(name).first().json || {};
  } catch (error) {
    return {};
  }
}

function clean(value, preserveNewLines = false) {
  let text = '';

  if (value === undefined || value === null) {
    text = '';
  } else if (typeof value === 'object') {
    try {
      text = JSON.stringify(value);
    } catch (error) {
      text = '';
    }
  } else {
    text = String(value);
  }

  text = text
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n');

  if (preserveNewLines) {
    return text
      .split('\n')
      .map(line => line.replace(/[ \t]+/g, ' ').trim())
      .filter(Boolean)
      .join('\n')
      .trim();
  }

  return text.replace(/\s+/g, ' ').trim();
}

