  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value, true);
    if (text) return text;
  }
  return '';
}

function extractInterpretedMessage(data) {
  const msg = data?.message;

  if (typeof msg === 'string') {
    return {
      content: clean(msg, true),
    };
  }

  if (msg && typeof msg === 'object') {
    return {
      ...msg,
      content: firstFilled(
        msg.content,
        msg.text,
        msg.transcription,
        msg.transcribed_text,
        msg.interpreted_message,
        msg.message
      ),
    };
  }

  return {
    content: firstFilled(
      data?.content,
      data?.text,
      data?.transcription,
      data?.transcribed_text,
      data?.interpreted_message,
      data?.output,
      data?.message
    ),
  };
}

function classifyBusinessKnowledgeNeed(text) {
  const value = clean(text)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

  const looksLikeQuestion =
    /[?？]/.test(value) ||
    /\b(onde|qual|quais|quanto|quando|como|pode|posso|vocês|voces|tem|aceita|funciona|fica|abre|fecha|custa|valor|preço|preco)\b/i.test(value);

  const looksLikePetDataOnly =
    !looksLikeQuestion &&
    /\b(anos?|meses?|macho|fêmea|femea|castrado|castrada|não castrado|nao castrado|raça|raca|porte|pequeno|médio|medio|grande|dachshund|shihtzu|shih tzu|spitz|vira-lata|srd)\b/i.test(value);

  if (looksLikePetDataOnly) {
    return {
      needs_business_knowledge: false,
      intents: [],
    };
  }

  const checks = [
    ['localizacao_endereco', /\b(onde fica|onde vocês ficam|localiza|localização|endereço|bairro|cidade|unidade|patamares|amaralina|pituba|salvador)\b/i],
    ['preco_valor', /\b(preco|valor|diaria|mensal|plano|pacote|quanto custa|custa quanto|taxa|avaliacao)\b/i],
    ['horario_funcionamento', /\b(horário|horario|funciona|funcionamento|abre|fecha|check[- ]?in|check[- ]?out)\b/i],
    ['servicos_regras', /\b(creche|hotel|hospedagem|adaptação|adaptacao|adestramento|transporte|buscar|levar|pegar|trazer|vacina|antipulgas|vermifug)\b/i],
    ['racas_restricoes', /\b(raça|raca|porte|pitbull|rottweiler|akita|american bully|macho não castrado|castrado|cio|idoso)\b/i],
    ['pagamento', /\b(pix|pagamento|paguei|comprovante|boleto|depósito|deposito|transferência|transferencia)\b/i],
  ];

  const intents = checks
    .filter(([, regex]) => regex.test(value))
    .map(([name]) => name);

  return {
    needs_business_knowledge: intents.length > 0,
    intents,
  };
}

const entrada = readNode('Converter Payload');
const interpretacao = readNode('Interpreta Audio ou Texto');
const historico = readNode('Busca Histórico Chatwoot');

const baseMessage = asObject(entrada.message || $json.message);
const interpretedMessage = extractInterpretedMessage(interpretacao);

const baseContent = clean(baseMessage.content, true);
const baseContentForAi = clean(baseMessage.content_for_ai, true);
const interpretedContent = clean(interpretedMessage.content, true);

const finalContent = firstFilled(
  interpretedContent,
  baseContent,
  baseContentForAi,
  entrada.chatInput,
  $json.chatInput
);

const message = {
  ...baseMessage,
  ...interpretedMessage,
  content: finalContent,
  content_raw: baseContent,
  content_before_interpretation: baseContent,
