  has_text: Boolean(finalContent),
  has_attachment: baseMessage.has_attachment === true,
  content_type: baseMessage.content_type || baseMessage.message_modality || interpretedMessage.content_type || interpretedMessage.message_modality || 'text_only',
  message_modality: baseMessage.message_modality || baseMessage.content_type || interpretedMessage.message_modality || interpretedMessage.content_type || 'text_only',
  data_url: baseMessage.data_url || interpretedMessage.data_url || null,
