};

const historyText = clean(historico.history_text || $json.agent?.history_text, true);
const historyForBruna = clean(historico.history_for_agent || $json.agent?.history_for_agent, true);

const currentForIntent = [
  finalContent,
  baseContent && baseContent !== finalContent ? baseContent : '',
  interpretedContent && interpretedContent !== finalContent ? interpretedContent : '',
].filter(Boolean).join('\n');

const businessNeed = classifyBusinessKnowledgeNeed(currentForIntent);

const queryParts = businessNeed.needs_business_knowledge
  ? [
      finalContent ? `Mensagem atual: ${finalContent}` : '',
      baseContent && baseContent !== finalContent ? `Texto/legenda original: ${baseContent}` : '',
      interpretedContent && interpretedContent !== finalContent ? `Interpretação da mídia: ${interpretedContent}` : '',
      businessNeed.intents.length ? `Assuntos detectados: ${businessNeed.intents.join(', ')}` : '',
