      }
    }
  }
];

function readNode(name) {
  try {
    return $(name).first().json || {};
  } catch (error) {
    return {};
  }
}

function clean(value, preserveNewLines = false) {
  let text = '';

  if (value === undefined || value === null) {
    text = '';
  } else if (typeof value === 'object') {
    try {
      text = JSON.stringify(value);
    } catch (error) {
      text = '';
    }
  } else {
    text = String(value);
  }

  text = text
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n');

  if (preserveNewLines) {
    return text
      .split('\n')
      .map(line => line.replace(/[ \t]+/g, ' ').trim())
      .filter(Boolean)
      .join('\n')
      .trim();
  }

  return text.replace(/\s+/g, ' ').trim();
}

function asObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value, true);
    if (text) return text;
  }
  return '';
}

function extractInterpretedMessage(data) {
  const msg = data?.message;

  if (typeof msg === 'string') {
    return {
      content: clean(msg, true),
    };
  }

  if (msg && typeof msg === 'object') {
    return {
      ...msg,
      content: firstFilled(
        msg.content,
        msg.text,
        msg.transcription,
        msg.transcribed_text,
        msg.interpreted_message,
        msg.message
      ),
    };
  }

  return {
    content: firstFilled(
      data?.content,
      data?.text,
      data?.transcription,
      data?.transcribed_text,
      data?.interpreted_message,
      data?.output,
      data?.message
    ),
  };
}

function classifyBusinessKnowledgeNeed(text) {
  const value = clean(text)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

  const looksLikeQuestion =
    /[?？]/.test(value) ||
    /\b(onde|qual|quais|quanto|quando|como|pode|posso|vocês|voces|tem|aceita|funciona|fica|abre|fecha|custa|valor|preço|preco)\b/i.test(value);

  const looksLikePetDataOnly =
    !looksLikeQuestion &&
    /\b(anos?|meses?|macho|fêmea|femea|castrado|castrada|não castrado|nao castrado|raça|raca|porte|pequeno|médio|medio|grande|dachshund|shihtzu|shih tzu|spitz|vira-lata|srd)\b/i.test(value);

  if (looksLikePetDataOnly) {
    return {
      needs_business_knowledge: false,
      intents: [],
    };
  }

  const checks = [
    ['localizacao_endereco', /\b(onde fica|onde vocês ficam|localiza|localização|endereço|bairro|cidade|unidade|patamares|amaralina|pituba|salvador)\b/i],
    ['preco_valor', /\b(preco|valor|diaria|mensal|plano|pacote|quanto custa|custa quanto|taxa|avaliacao)\b/i],
    ['horario_funcionamento', /\b(horário|horario|funciona|funcionamento|abre|fecha|check[- ]?in|check[- ]?out)\b/i],
    ['servicos_regras', /\b(creche|hotel|hospedagem|adaptação|adaptacao|adestramento|transporte|buscar|levar|pegar|trazer|vacina|antipulgas|vermifug)\b/i],
    ['racas_restricoes', /\b(raça|raca|porte|pitbull|rottweiler|akita|american bully|macho não castrado|castrado|cio|idoso)\b/i],
    ['pagamento', /\b(pix|pagamento|paguei|comprovante|boleto|depósito|deposito|transferência|transferencia)\b/i],
  ];

  const intents = checks
    .filter(([, regex]) => regex.test(value))
    .map(([name]) => name);

  return {
    needs_business_knowledge: intents.length > 0,
    intents,
  };
}

const entrada = readNode('Converter Payload');
const interpretacao = readNode('Interpreta Audio ou Texto');
const historico = readNode('Busca Histórico Chatwoot');

const baseMessage = asObject(entrada.message || $json.message);
const interpretedMessage = extractInterpretedMessage(interpretacao);

const baseContent = clean(baseMessage.content, true);
const baseContentForAi = clean(baseMessage.content_for_ai, true);
const interpretedContent = clean(interpretedMessage.content, true);

const finalContent = firstFilled(
  interpretedContent,
  baseContent,
  baseContentForAi,
  entrada.chatInput,
  $json.chatInput
);

const message = {
  ...baseMessage,
  ...interpretedMessage,
  content: finalContent,
  content_raw: baseContent,
  content_before_interpretation: baseContent,
  content_for_ai: finalContent,
  has_text: Boolean(finalContent),
  has_attachment: baseMessage.has_attachment === true,
  content_type: baseMessage.content_type || baseMessage.message_modality || interpretedMessage.content_type || interpretedMessage.message_modality || 'text_only',
  message_modality: baseMessage.message_modality || baseMessage.content_type || interpretedMessage.message_modality || interpretedMessage.content_type || 'text_only',
  data_url: baseMessage.data_url || interpretedMessage.data_url || null,
  media_type: baseMessage.media_type || interpretedMessage.media_type || '',
};

const historyText = clean(historico.history_text || $json.agent?.history_text, true);
const historyForBruna = clean(historico.history_for_agent || $json.agent?.history_for_agent, true);

const currentForIntent = [
  finalContent,
  baseContent && baseContent !== finalContent ? baseContent : '',
  interpretedContent && interpretedContent !== finalContent ? interpretedContent : '',
].filter(Boolean).join('\n');

const businessNeed = classifyBusinessKnowledgeNeed(currentForIntent);

const queryParts = businessNeed.needs_business_knowledge
  ? [
      finalContent ? `Mensagem atual: ${finalContent}` : '',
      baseContent && baseContent !== finalContent ? `Texto/legenda original: ${baseContent}` : '',
      interpretedContent && interpretedContent !== finalContent ? `Interpretação da mídia: ${interpretedContent}` : '',
      businessNeed.intents.length ? `Assuntos detectados: ${businessNeed.intents.join(', ')}` : '',
      historyForBruna ? `Contexto recente curto: ${historyForBruna.split('\n').slice(-5).join(' | ')}` : '',
    ]
  : [
      finalContent ? `Mensagem atual: ${finalContent}` : '',
    ];

const baseSearchQuery = queryParts
  .filter(Boolean)
  .map(value => clean(value, true))
  .filter(Boolean)
  .join('\n\n')
  .slice(0, 2500);

return [
  {
    json: {
      ...$json,
      ...entrada,
      message,
      agent: {
        ...asObject(entrada.agent),
        ...asObject($json.agent),
        history_text: historyText,
        history_for_agent: historyForBruna,
        current_message_after_interpretation: finalContent,
        needs_business_knowledge: businessNeed.needs_business_knowledge,
        business_knowledge_intents: businessNeed.intents,
        knowledge_query: baseSearchQuery,
      },
      chatInput: finalContent,
      should_search_knowledge_base: businessNeed.needs_business_knowledge,
      base_search_query: businessNeed.needs_business_knowledge
        ? baseSearchQuery
        : '',
      debug: {
        ...asObject($json.debug),
        monta_query_base_version: 'v1_merge_normaliza_interpretacao_historico',
        base_content: baseContent,
        interpreted_content: interpretedContent,
        final_content: finalContent,
        has_history_for_agent: Boolean(historyForBruna),
        needs_business_knowledge: businessNeed.needs_business_knowledge,
        business_knowledge_intents: businessNeed.intents,
      },
    },
  },
];

